var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하하……. 갑작스럽게 불려나와서 브리핑하려니 좀 긴장되네요.","JPN":"あはは……急に呼び出されてブリーフィングするって、ちょっと緊張しますね。","ENG":"Ahaha... Kinda nervous to suddenly get called in to do a briefing...","TWN":"哈哈哈……突然把人家找來做簡報，害我有點緊張呢～"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"크흠. 우선, 저희는 알파트릭스 바이오닉스에 대해 조사하고 있었는데 말이죠.","JPN":"ゴホン。まず、私たちはアルファトリックス・バイオニクスについて\\n調べていました。","ENG":"Ahem. First off, we did some investigating into Alphatrix’s Bionics.","TWN":"咳咳，我們一直有在調查阿爾法崔克斯仿生，"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"회사는 건실하게 운영되었지만, 몇 년 전부터 대표는 전혀 얼굴을 드러내지 않고 있었어요.","JPN":"会社は堅実に運営されていましたが、数年前から代表は\\nまったく公に顔を出していませんでした。","ENG":"The company itself has been operating well, but we found that the CEO hadn’t shown up there in years.","TWN":"公司的營運雖然沒什麼問題，但代表從幾年前開始就沒有再露過面。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우연인지는 모르겠지만, 그 시점은 회장님의 사망 시기와 일치하고요.","JPN":"偶然かもしれませんが、そのタイミングは会長の死亡時期と\\n一致しています。","ENG":"I don’t know if it’s a coincidence or not, but that timeline coincides with the President’s passing.","TWN":"不知道是不是巧合，但會長也在同個時間點死亡。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그리고 또 하나 수상한 점이라면……","JPN":"そしてもう一つ怪しい点といえば……","ENG":"Another thing that seemed suspicious was...","TWN":"另外還有一點很可疑……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"부회장님이 돌아가시기 전에 바이오닉스 대표의 지분 중 상당량이 처분된 뒤였어요.","JPN":"副会長が亡くなる前に、バイオニクス代表の持株の相当量を\\n処分したそうです。","ENG":"That a significant portion of the CEO of Bionics' shares were disposed of before the Vice Chairman died.","TWN":"就是在副會長遭到殺害前，仿生代表正好將持有的股份大量拋出。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서 그 돈이 흘러들어간 곳을 추적하던 중에 이상한 정황이 드러났어요.","JPN":"そして、そのお金の流れを追跡していたところ、不可解な状況が\\n明らかになりました。","ENG":"So we tracked where the money went and found something interesting.","TWN":"我們追查那筆錢的流向後，發現一件可疑的事。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"익명의 개인 투자자가 최근 막대한 자금으로 퓨처 앳 워의 지분을 매입하고 있다는 거죠.","JPN":"匿名の個人投資家が最近、莫大な資金でフューチャーアットウォーの\\n株を買収していたのです。","ENG":"Huge sums of money have been spent by an anonymous investor on Future-at-War shares.","TWN":"有一位匿名的投資人，最近大量買入天啟兵器的股份。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"저희는 그 개인 투자자가 알파트릭스 바이오닉스 대표와 관련이 있다고…….","JPN":"私たちはその個人投資家がアルファトリックス・バイオニクス代表と\\n関連があると……","ENG":"We suspect that this individual is somehow connected to the CEO of Bionics...","TWN":"我們懷疑，那位投資人和阿爾法崔克斯仿生的代表有關係……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"갑자기 처들어와서 무슨 행패인가! 썩 안 나가!","JPN":"いきなり乱入してなんて乱暴な発言だ！　さっさと出ていけ！","ENG":"Are you here to waste our time or what?! Get out!!","TWN":"你們突然這樣衝進來，跟流氓有什麼兩樣！都給我滾出去！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"계속 들어보죠, 이사님.","JPN":"続きを聞いてみましょう、理事。","ENG":"Let’s first let her finish.","TWN":"理事，請繼續聽下去。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"계속하긴 뭘! 이 자리는 알파트릭스의 새로운 회장을 추대하는 이사회의야!","JPN":"続ける必要などない！\\nここはアルファトリックスの新しい会長を推戴する理事会だ！","ENG":"Let her finish?! This meeting was scheduled to discuss who will be the President of Alphatrix!","TWN":"聽什麼聽！董事會的職責，是要推選出阿爾法崔克斯的新任會長！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"주주들도 참석한 자리에서 저런 얼토당토 않은 비약을 늘어놔서 어쩌잔 건가!","JPN":"株主たちも出席している場で、あんなデタラメな憶測を並べてどうするつもりだ！","ENG":"Our shareholders are also present and you still want them to hear her sell us snake oil?!","TWN":"這麼多股東在場聽他們說那些毫無根據的推測，這是在幹什麼！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"당장 저 두 사람을 끌어내!","JPN":"今すぐあの二人を追い出せ！","ENG":"Get those two out of here this instant!","TWN":"立刻把那兩個人給我趕出去！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨, 이사님. 저는 지금 제 권리를 행사 중이에요.","JPN":"それはできません、理事。私は今、自分の権利を行使しています。","ENG":"No, sir. I am just exercising my right.","TWN":"不可以，我正在行使我的權利。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"권리 행사라니……. 무슨 얘깁니까?","JPN":"権利の行使とは……どういうことでしょう？","ENG":"Your right? What are you talking about?","TWN":"行使什麼權利……你在說什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저도 회장 후보로 입후보했잖아요?","JPN":"私も会長候補として立候補したでしょう？","ENG":"I am a candidate for the President seat, am I not?","TWN":"我不是會長候選人嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저에게 허락된 연설 시간 동안에는 어떤 말이든 자유롭게 할 권리가 있어요.","JPN":"私に許可されたスピーチの時間中は、どんな発言でも\\n自由に話す権利があります。","ENG":"I've got my time allotted for my speech. It is my right to use that time however I see fit.","TWN":"那麼，只要是在我的發表時間內，我要講什麼是我的自由吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그래서 이렇게 사건을 담당하신 강소영 경위님을 모신 거죠.","JPN":"それで、このように事件を担当されているマエカワ警部補をお招きしたのです。","ENG":"That's why I brought Lieutenant Kang, who is in charge of the case, here.","TWN":"所以我才把負責這次事件的姜素英警衛請過來，"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이 회의에 참석하신 주주님들께서도 아셔야 할 이야기라고 생각하니까요.","JPN":"この会議にご出席された株主の皆様も知っておくべき話だと思いますので。","ENG":"I thought our shareholders also had a right to know what’s going on.","TWN":"因為我認為，這些事在座的股東們都需要知道。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"크흠…… 자네답지 않게 왜 그러는 건가?","JPN":"コホン……君らしくないぞ。どうしたんだ？","ENG":"Ahem... Why are you acting like a different person all of a sudden?","TWN":"咳咳……為什麼要這樣？這不像你。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"억울한 누명을 썼다는 건 다들 알아.","JPN":"悔しい濡れ衣を着せられたことは皆承知している。","ENG":"We all know you were framed.","TWN":"大家都知道你被冤枉，"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"하지만 이런 중요한 날에 이미 끝난 일을 들먹이는 건 다 죽자는 것 아닌가?","JPN":"だが、このような大事な日に既に終わったことを口にするのは、\\n自滅しようとしているようにしか見えないが？","ENG":"But that’s no reason to waste everyone’s time on a closed case!","TWN":"只是為什麼要挑今天這麼重要的日子，把已經結束的事又拿出來講，你是要大家一起死嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"끝나지 않았어요. 고모님은 실종 상태고, 고모님을 지원한 세력에 대해서도 모르니까요.","JPN":"まだ終わっていません。叔母様は行方不明ですし、\\n叔母様を支援していた勢力についても、まだ突き止めていません。","ENG":"It’s not over yet. Aunt Cecilia is missing, and we do not know who she is working with.","TWN":"事情還沒結束，姑姑現在下落不明，也還不知道是誰在背後協助姑姑的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 할아버님이 추진하셨던 프로젝트도…….","JPN":"そしてお祖父様が推進したプロジェクトも……","ENG":"Also, the project my grandfather pushed for...","TWN":"還有爺爺生前推動的計畫……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"그만! 그만 좀 하게!","JPN":"もういい！　いい加減にしなさい！","ENG":"Okay! That's enough!","TWN":"夠了！別再說了！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"후우……. 좋아. 이렇게 함세.","JPN":"ふう……わかった、こうするとしよう。","ENG":"Ugh... All right. How about this, then?","TWN":"哀……那這樣吧！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"내가 꼭 약속하지. 새로운 회장님께 사건의 철저한 조사와 관계자에 대한 엄벌을 말이야.","JPN":"私が必ず約束する。新しい会長に対して、事件の徹底した調査と\\n関係者に対する厳罰をね。","ENG":"I promise you that the new President will reinvestigate and punish whoever was involved in this case.","TWN":"我答應你，新任的會長一定會把這件事徹查清楚，相關人士決不寬貸！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"정말요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"물론이지. 그러니 이 자리에서는…….","JPN":"もちろんだ。だからもうこの場では……","ENG":"Of course. So if you will...","TWN":"當然，所以……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그럼 역시 제가 회장이 되어야겠네요.","JPN":"でしたらやはり私が会長にならないといけませんね。","ENG":"Then, I believe that I should be the next President.","TWN":"那只好我當會長囉！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"뭐……? 그게 무슨……?","JPN":"は……？　それはどういう……？","ENG":"Huh? What do you mean?","TWN":"什……？你說什麼……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저도 사건의 철저한 조사와 관계자에 대한 엄벌을 희망하거든요.","JPN":"私も事件の徹底した調査と関係者に対する厳罰を希望しています。","ENG":"I also hope to reinvestigate and punish whoever was involved.","TWN":"因為我也希望可以查清楚，而且嚴懲相關人士。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그러면 제가 회장을 맡으면 되지 않을까요?","JPN":"だから私が会長を務めればいいと思いませんか？","ENG":"Then wouldn’t I be the best fit for President?","TWN":"那我不就是會長的最佳人選嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그러면 이상으로 제 연설은 마치겠습니다.","JPN":"それでは以上を持ちまして、私のスピーチを終わります。","ENG":"That will conclude my speech. Thank you.","TWN":"我的發表到此為止。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"갑자기 연락 주셔서 나오긴 했는데 분위기가 영 별로네요.","JPN":"急に連絡をいただいて出席しましたが、雰囲気があまり良くありませんね。","ENG":"I came in a hurry because you called, but the vibe here isn’t great, is it?","TWN":"因為你突然找我，我才過來的，沒想到氣氛這麼凝重！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그럴 거예요. 원래 정해 놓은 결과를 확인만 하는 자리거든요.","JPN":"そうですね。元々決めておいた結果を確認するだけの集まりなんです。","ENG":"I expected it to be so. This was supposed to be a formality meeting.","TWN":"正常的，畢竟那個會議中，通常只是通知大家已經決定的事而已。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"쭉 그룹에서 소외되었던 제가 갑자기 회장직을 원한다고 하니 당황하는 것도 당연하겠죠.","JPN":"ずっとグループから疎外されていた私が急に会長職を望んでいるなんて\\n言うから、慌てるのも当然でしょう。","ENG":"But, as I have expressed my desire for the position of President, I'm sure most of them are perplexed.","TWN":"但一直被集團冷落的我突然說要當會長，大家一定會嚇到的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"무섭지는 않아요? 아무것도 모르는 아가씨로 남아 있으면 다들 건드리지 않을 텐데?","JPN":"怖くはないんですか？　世間知らずのお嬢様として残っていれば、\\n敵視されることはないと思いますが。","ENG":"Aren’t you scared? Wouldn’t it be better to stay as the girl who doesn’t know anything?","TWN":"你不怕嗎？你不把事情搬上檯面的話，其他人應該也不會招惹你吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"무섭기는 해요. 그동안 해 본 적 없는 일이니까요.","JPN":"怖い気持ちはあります。今までやったことのないことですから。","ENG":"I am scared. But it’s because this is something I’ve never done before.","TWN":"當然怕，我從來沒這麼做過。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇지만……. 지금은 그것보다 제 스스로 선택하지 못하고 상황에 끌려가는 게 더 무서워요.","JPN":"でも……今はそれよりも自ら選択できず、その時の状況に引きずられる方が\\nもっと怖いです。","ENG":"What scares me the most is that all of this will end without my having any say in the matter.","TWN":"不過……我現在更怕的是無法自己做決定，被人牽著鼻子走。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"그러면 일렉트로닉스 대표와 이노베이션 대표의 연설이 모두 끝났으니…….","JPN":"それではエレクトロニクス代表とイノベーション代表のスピーチが終わりましたので……","ENG":"Then, since both candidates’ speeches have ended...","TWN":"電子代表和改革改革都已經發表完畢……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"선출을 진행하겠습니다. 선출 방식은…….","JPN":"選出を進めます。選出方法は……","ENG":"We will continue with the election. The method of selection is...","TWN":"接著就開始進行投票，投票方式是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"음? 누가 식이 진행 중인데 함부로 들어와?","JPN":"うむ？　会議中に勝手に入ってくるなんて、誰だ？","ENG":"Hmm? Who are you to disturb our meeting?","TWN":"嗯？是誰擅自在會議中把門打開？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런. 미안하게 됐군. 한창 바쁜 시기다 보니 조금 늦어졌어.","JPN":"やれやれ、申し訳ないことをしたな。忙しい時期なので少々遅れてしまった。","ENG":"Oh, my apologies for being late. I had some business to take care of first.","TWN":"哎呀～真是不好意思，我來晚了，你們正在忙吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저 말투랑 목소리는……. 사장님?","JPN":"この話し方と声は……社長？","ENG":"That voice... Boss?","TWN":"那個語氣和聲音……是老闆？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"왜 그래요? 혹시 저 분이랑 아는 사이세요?","JPN":"どうしました？　あの方とは知り合いですか？","ENG":"Hmm? Do you know this person?","TWN":"嗯？你認識他嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"선출식에 참석할 수 있는 자격은 제한되어 있어요.","JPN":"選出総会に参席できる資格は制限されています。","ENG":"I’m sorry, but the qualification to attend the election ceremony is limited.","TWN":"這個會議不是誰都有資格參加的，"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"경호원들을 어떻게 따돌렸는지 몰라도 어서 나가 주시죠.","JPN":"ガードたちをどうやってごまかしたのかはわかりませんが、早急にお引き取りを。","ENG":"I don’t know how you got through security, but I must ask you to leave.","TWN":"我是不清楚你是怎麼避開保全的，但請你立刻離開！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정 말게. 자격이라면 차고 넘칠 만큼 있으니까.","JPN":"心配するな。資格なら余るほどあるんだ。","ENG":"Don’t worry about it. I’m more than qualified to attend.","TWN":"別擔心，要說到資格的話，我可是超有資格！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"뭐야? 가만히 듣고 있으니까 이 자가 어쩌자고……!","JPN":"何だと？　こいつ何を言って……！","ENG":"What? Who are you to decide that?! I demand that...!","TWN":"什麼？你以為你是誰……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"회장과 한 약속을 지키기 위해서지. 그러니 조용히 해 주게.","JPN":"会長との約束を守るためだ。だから静かにしてくれ。","ENG":"Please, stop shouting. I’m here to keep my promise to my old friend.","TWN":"我是來遵守和會長之間的約定的，其他人麻煩安靜點。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"이 서류는…….","JPN":"この書類は……","ENG":"That document...","TWN":"這些資料是……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"자, 잠깐……. 이거…….","JPN":"ま、待て……これは……","ENG":"W-wait... That means...","TWN":"等等……這是……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"갑자기 왜 그러십니까? 무슨 내용인데요?","JPN":"急にどうされました？　どんな内容ですか？","ENG":"What’s going on? What does it say?","TWN":"你怎麼啦？上面寫什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"저, 저희 그룹의 최대 주주께서……. 이런 젊은 분이실 거라고는…….","JPN":"わ、我がグループの筆頭株主が……まさかこんな若い方だったとは……","ENG":"O-our majority shareholder... I didn’t take you to be so young...","TWN":"我…我們集團最大的股東……竟然這麼年輕……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"칭찬 고맙군, 내가 나이에 비해서 젊어 보이긴 하지.","JPN":"お褒めいただきありがとう。確かに、私は年の割に若く見える方だ。","ENG":"I appreciate the compliment. I do look younger than my age.","TWN":"謝謝你的稱讚，我看起來是比實際年齡小沒錯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자. 이 메모리 토큰에는 생전에 알파트릭스 회장이 남긴 유언장이 들어 있다네.","JPN":"さあ、このメモリートークンには、生前にアルファトリックス会長が遺した\\n遺言状が入っている。","ENG":"Here. In this Memory Token is the will of Alphatrix’s late President.","TWN":"這個硬碟裡有阿爾法崔克斯會長生前留下的遺囑。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"조건을 달성하면 차기 회장을 선출하는 자리에서 공개해 달라고 내게 부탁했지.","JPN":"ある条件を達成したら次期会長を選出する場で公開してほしいと\\n頼まれてな。","ENG":"He requested that I share it if a certain condition was met during the next election.","TWN":"他拜託我當條件滿足後，就在選出下一任會長的會議中公開。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"잠깐만요. 말도 안 됩니다. 회장님의 유언장은 그룹 전체가 찾아도 발견되지 않았어요.","JPN":"お待ちください。あり得ない話です。会長の遺言状はグループ全体をあげて\\n探しましたが見つかりませんでした。","ENG":"Wait a minute. That’s impossible. No one at the company could find any shred of evidence of the President’s will anywhere.","TWN":"先等一下，你在胡說什麼！我們翻遍整個集團都沒找到會長的遺囑！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"당연하지. 회장이 유언장의 소재가 알려지지 않길 바랐으니까.","JPN":"当然だ。会長は遺言状の所在が知らされないことを望んだからな。","ENG":"Of course you didn’t. He didn’t want any of you to know its whereabouts.","TWN":"那當然，因為會長並不希望被人知道遺囑的存在。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이번 사건만 봐도 왜 그랬는지는 충분히 이해가 되지 않나?","JPN":"今回の事件をみれば、なぜそうしたのかは十分理解できないかね？","ENG":"Can’t you tell why, from what has happened around here recently?","TWN":"光看這次的事件，不就可以理解會長的用意嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"그, 그런…….","JPN":"そ、そんな……","ENG":"Th-that’s...","TWN":"這……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저, 사장…… 아니, 최대 주주님.","JPN":"あの、社長……いえ、筆頭株主様。","ENG":"B-boss.... I mean, sir...","TWN":"老……不對，最大股東先生。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L49_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그럼 할아버님이 말씀하신 조건이 뭔가요?","JPN":"では、お祖父様がおっしゃった条件とは何でしょう？","ENG":"Could you tell us what that condition might be?","TWN":"請問爺爺說的條件是指什麼呢？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네일세. 지아 양.","JPN":"君だよ、ユイ君。","ENG":"It’s you, Jia.","TWN":"就是你，沈佳。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"회장이 말한 조건은 자네가 회장 선거에 입후보할 경우였어.","JPN":"会長が言った条件は、君が選出総会に立候補することだった。","ENG":"The condition was that you be a candidate for the position.","TWN":"會長所說的條件，就是你成為下一任會長的候選人。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"하지만…… 유언장이 조작되었을 가능성도…….","JPN":"しかし……遺言状がねつ造された可能性も……","ENG":"But... Isn’t there the possibility that the will has been tampered with...?","TWN":"可是……遺囑也有可能是造假的吧……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"크흠. 이사님, 저 메모리 토큰은 저희 일렉트로닉스의 제품입니다.","JPN":"コホン。理事、あのメモリートークンは弊社、エレクトロニクスの製品です。","ENG":"Ahem! That Token was made by Electronics.","TWN":"咳咳，理事，那個硬碟是我們電子的產品。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"위•변조도 불가능할 뿐더러, 정해진 정보 출력 횟수가 다하면 내부 데이터가 소거되게 되어 있어요.","JPN":"偽造・変造も不可能なだけでなく、定められた情報出力回数を超えると\\n内部データが消去されるようになっています。","ENG":"Not only is it impossible to forge or tamper with, but the internal data is erased once it reaches the set maximum number of available plays.","TWN":"不僅無法偽造跟竄改，而且設定的播放次數使用完畢後，裡面的資料就會自動消失。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"메모리 토큰에 설정된 출력 횟수는 1회일세.","JPN":"メモリートークンに設定された出力回数は1回だ。","ENG":"This token’s print count is set to 1.","TWN":"這個硬碟設定的播放次數是一次。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 말은 나도 이 안에 어떤 유언이 담겨 있는지는 모른다는 말이야.","JPN":"それはつまり、私もこの中にどんな遺言が入っているかわからないということだ。","ENG":"In other words, I don’t know what is inside the will either.","TWN":"意思就是，我也不知道遺囑的內容是什麼。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자, 그럼 한 번 다들 들어 보게나.","JPN":"では、みんなで聞いてみよう。","ENG":"Okay then, let’s all hear what it says.","TWN":"那大家就一起來欣賞吧！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"나는……. 이 유언이 내 스스로의 의지로 남긴 것임을 밝힌다.","JPN":"私は……この遺言が自らの意志で残したものであることを明言する。","ENG":"I... declare that I leave this will on my own accord.","TWN":"這個遺囑……是根據我本人的意願寫下來的。"},"stage":{"bg":"ALPHA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그 분께 맡긴 유언이 공개되었다는 말인 즉……. 지아가 회장직에 입후보했다는 뜻이겠지.","JPN":"あの方に預けた遺言が公開されたということはつまり……\\nユイが会長職に立候補したということだろう。","ENG":"If this will is being heard, that means that Jia has expressed her will to become President.","TWN":"當這份遺囑被公開時……也就是表示小佳成為會長的候選人。"},"stage":{"bg":"ALPHA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"지아야, 나는 네가 <color=#ffd34c>더 나은 세상</color>을 만들어 주리라고 믿는다.","JPN":"ユイ、私はお前が<color=#ffd34c>より良い世界</color>を作ってくれると信じている。","ENG":"Jia, I have full confidence that you will make <color=#ffd34c>the world a better place</color>.","TWN":"小佳，我相信你能打造出<color=#ffd34c>更好的未來</color>。"},"stage":{"bg":"ALPHA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"나 같은 인간의 방식이 아니라……. 더 나은 형태로.","JPN":"私のような人間のやり方ではなく……より良い形でな。","ENG":"Not by conventional human means, but by means far beyond our imagination.","TWN":"但不是用我這種人的方式……而是更好的方法。"},"stage":{"bg":"ALPHA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그 분께서 관여하지 않으셨다는 건……. 네가 너의 의지로 그 자리에 섰을 테니 말이다.","JPN":"あの方が関与されなかったということは……お前が自分の意志でその場に立っているのだろう。","ENG":"If The Eminent wasn't involved… You decided to step up yourself.","TWN":"那位沒有插手干預……就表示是你自願坐上那個位置的。"},"stage":{"bg":"ALPHA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"……그러니 동석하고 있는 사람들 모두 듣게.","JPN":"……だから同席している者はみんな聞きなさい。","ENG":"So, to everyone else present in the room, listen carefully.","TWN":"……因此在場的人都聽著！"},"stage":{"bg":"ALPHA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"나는, 이 유언이 공개된 시점부터 내 명의로 된 모든 특허권을 지아에게 넘길 걸세.","JPN":"私は、この遺言が公開された時点から私名義のすべての特許権を\\nユイに委ねることにする。","ENG":"I am handing over all patents under my name to Jia from the moment this will is played.","TWN":"以這份遺囑公開的時間點為準，我要將我名下所有的專利都交給小佳！"},"stage":{"bg":"ALPHA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"판단에 도움이 되길 바라네. 결정은 남은 자들 몫일 테니.","JPN":"判断に役立つことを祈る。決定は残された者たちの役目だからな。","ENG":"I hope this helps in making your decision. As that is your right...","TWN":"希望這會有助於你們的判斷，剩下的就交給你們決定吧。"},"stage":{"bg":"ALPHA_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"회장 명의로 된 특허권이 전부 저 여자애한테 넘어간다고?","JPN":"会長名義の特許権を全部あの女の子に渡すと？","ENG":"All patents are going to that girl?","TWN":"會長要將他名下所有的專利都交給那女孩？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"아니, 법적으로 가능한 게 맞나? 알파트릭스의 핵심 기술들은 전부 회장 명의로 되어 있잖아?","JPN":"いや、法的に可能なのか？　アルファトリックスの核心技術は全部\\n会長名義になっているだろう？","ENG":"Is that even legal?! Aren’t all of Alphatrix’s core technology under the President’s name?","TWN":"等等，就法律而言是可行的嗎？阿爾法崔克斯核心技術的專利不都在會長名下嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님…….","JPN":"お祖父様……","ENG":"Grandfather...","TWN":"爺爺……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"이, 이건……. 이렇게 되면…….","JPN":"こ、これは……こうなると……","ENG":"This... Can’t be...","TWN":"這……這樣的話……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"이제 그만 포기합시다.","JPN":"もう諦めましょう。","ENG":"There’s no use in fighting this.","TWN":"放棄吧！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"사람들 표정을 보세요. 이미 추가 기울어 버렸어요.","JPN":"皆さんの反応を見てください。すでに決まったようなものです。","ENG":"Look at their faces. They’ve already made up their minds.","TWN":"你看看大家表情，現在是大勢已去。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오랜만에 햇볕을 쬐니 좋군.","JPN":"久々の日光は気持ちがいいな。","ENG":"I haven’t seen the sun in a long time.","TWN":"好久沒曬太陽了，真舒服！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"부사장 말대로 가끔은 직접 바깥 바람도 쐬어 주는 게 좋겠어.","JPN":"副社長の言うとおり、たまには直接外の風に当たってみるのも悪くないだろう。","ENG":"Maybe I should take up on the Vice President’s words and get some fresh air once in a while.","TWN":"副社長說的沒錯，偶爾還是需要到外面透透氣的。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"자, 잠깐만요! 사장님!","JPN":"ま、待ってください！　社長！","ENG":"W-wait! Boss!","TWN":"請…請等下！老闆！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런, 신임 회장님 아닌가. 그렇게 뛰다가 넘어지면 어쩌려고.","JPN":"おっと、新任会長じゃないか。そんなに慌てて走ったら転んでしまうぞ。","ENG":"Why, if it isn’t our new President. Be careful now, you might trip and get hurt.","TWN":"哎呀，這不是新任會長嗎？別跑了，小心跌倒。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"괜찮아요! 저 17센티미터 힐을 신고도 100미터를 5초 안에 끊은 적 있거든요!","JPN":"大丈夫です！　私、17cmのハイヒールを履いて100mを5秒以内で\\n走ったこともあるんです！","ENG":"I’m okay! I even ran 100 meters in 5 seconds with 17cm heels on once!","TWN":"沒事的！我曾經穿17公分的高跟鞋，在5秒內跑完100公尺喔！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아니, 말하고 싶은 건 이게 아니라……","JPN":"いえ、言いたいことはそれじゃなくて……","ENG":"Oh wait... That’s not what I wanted to say...","TWN":"不對，我想說的不是這個……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어째서 자네를 도와준 건지 궁금한가?","JPN":"どうして君を助けたのか、気になるのかね？","ENG":"You wanted to know why I helped you?","TWN":"你是好奇我為什麼要幫你嗎？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……네. 맞아요.","JPN":"……はい、そうです。","ENG":"Yes, will you tell me?","TWN":"……是的。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그야 간단하지. 친구이니까.","JPN":"それは単純さ。友達だからだ。","ENG":"That’s easy. It’s because we’re friends.","TWN":"我當然要幫你，因為我們是朋友啊！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……결국, 언젠가는 선택의 때가 온다네.","JPN":"……結局、いつかは選択の時が来る。","ENG":"...Eventually, the day will come when you have to make a choice.","TWN":"……結果選擇的時候始終會來的。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"누구의 간섭없이, 오롯이 스스로의 마음과 마주해야만 하는 그 때가.","JPN":"誰からの干渉もなく、ひたすらに自分の心と向き合わなければならない、そんな時が。","ENG":"A moment when you must confront your own heart without the help of others.","TWN":"沒有任何人的干涉，只有自己和自己內心對話的時刻。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 힘든 고비를 넘긴 친구를 도와 주는 건 친구로서 당연한 일 아닌가?","JPN":"そんな大変な時を乗り越えた友達を助けるのは、友達として\\n当たり前のことだと思わないか？","ENG":"Shouldn’t friends help each other out when going through tough times?","TWN":"幫助一位經歷過這麼多困難的朋友，這不是身為朋友該做的事嗎？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 도운 걸세. 자네도, 자네의 할아버지도.","JPN":"だから助けたんだ。君も、君の祖父も。","ENG":"That’s why I helped you and your grandfather.","TWN":"所以當然要幫你，還有你爺爺囉！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……역시 당신이 코핀 컴퍼니의 사장님이셨던 거군요.","JPN":"……やはりあなたがコフィンカンパニーの社長だったのですね。","ENG":"So you are the Boss of Coffin Company.","TWN":"……你果然是科芬公司的老闆沒錯！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"뭔가 비밀이 있는 분이란 건 알았지만 이렇게 멋진 분이실 줄은 몰랐어요.","JPN":"何か秘密がある方だとはわかっていましたが、こんなに素敵な方だとは\\n思いませんでした。","ENG":"I knew you had secrets, but I had no idea you were such a wonderful person.","TWN":"雖然我知道老闆有些不能說的秘密，不過沒想到老闆這麼帥。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미리 말하지 못한 건 사과하지. 내게도 개인적인 사정이 있어서 말이야","JPN":"前もって言えなかったことは謝るよ。私にも個人的な事情があってね。","ENG":"I’m sorry I didn’t tell you earlier. But I had my reasons not to.","TWN":"抱歉，沒能提前告訴你，但我也是有難言之隱。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사과 따윈 전혀 필요 없어요!","JPN":"謝る必要なんかちっともありません！","ENG":"You don’t need to apologize to me!","TWN":"完全不需要跟我道歉的！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"전 지금까지 세상 모든 일이 다 쉽게 느껴졌어요.","JPN":"私は今まで世の中のすべてのことが簡単だと感じていました。","ENG":"I always thought everything in life was easy.","TWN":"我以前一直以為世界上沒什麼事難得倒我的。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그저 할아버지의 말에 따르기만 하면 모든 것이 이루어 졌으니까요.","JPN":"ただお祖父様の言葉に従うだけで、すべてが叶いましたから。","ENG":"Because I got everything just by listening to my grandfather.","TWN":"因為我只需要照著爺爺的話去做，所有的事就會水到渠成。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 이번 일을 겪으면서 저 혼자서는 할 수 없는 일이 있다는 것도……","JPN":"ですが、今回のことを経験して、私一人ではできないことがあるということも……","ENG":"But after all this, I realize I can’t do everything alone, and...","TWN":"但經過這次的事，我才發現，原來也有我一個人辦不到的事……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제가 직접 선택해야 하는 일이 있다는 것도 알게 되었어요.","JPN":"私が自分で選択しなければならないことがあるということも知りました。","ENG":"That I have to make my own choices.","TWN":"也有我必須自己做出選擇的事。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사장님께서 가르쳐 주신 거죠.","JPN":"社長が教えてくれたのです。","ENG":"You taught me that.","TWN":"這都是老闆教會我的。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제게 뭔가를 가르쳐 주신 분은 할아버지 외에는 사장님이 처음이신 거에요.","JPN":"私に何かを教えてくれたのは、お祖父様以外は社長が初めてだったんです。","ENG":"You’re the first person who taught me something after my grandfather.","TWN":"除了爺爺之外，老闆是第一個教會我這些道理的人。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그러니까, 감사는 제가 드리고 싶어요.","JPN":"だから、感謝の言葉をお伝えしたいです。","ENG":"So, I want to say thank you.","TWN":"所以我想謝謝你。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사장님은…… 분명 무언가 힘들고 괴로운 일을 짊어지고 계시죠?","JPN":"社長は……きっと、なにか辛くて大変なことを背負っていらっしゃいますよね？","ENG":"Boss... I can tell something painful is eating away at you. Am I right?","TWN":"老闆……應該背負著很痛苦的事吧？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"전 알 수 있어요.","JPN":"私にはわかります。","ENG":"I can tell...","TWN":"我可以知道。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그게 무엇이든, 사장님의 일에 도움이 되고 싶어요.","JPN":"それが何であろうが、社長の仕事の役に立ちたいです。","ENG":"But whatever it is, I want to help you.","TWN":"不管是什麼事，我希望可以助老闆一臂之力。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사장님이 저에게 특별한 사람인 것처럼 저도 사장님께 특별한 사람이 되고 싶으니까요.","JPN":"社長が私にとって特別な人であるように、私も社長にとって特別な人に\\nなりたいですから。","ENG":"I want to be special to you because you are special to me.","TWN":"因為老闆對我而言是特別的人，而我也想成為對老闆而言特別的人。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제가 도움이 될 수 있는 일이 있을까요?","JPN":"私でお役に立てることがあれば、教えていただけませんか？","ENG":"Is there anything I can help you with?","TWN":"有什麼我可以幫老闆的嗎？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙군, 그렇다면 이쪽도 부탁할 게 있네.","JPN":"ありがとう。それなら私も頼みがあるんだ。","ENG":"Thanks. Actually, there is something.","TWN":"謝謝你，那我有件事想請你幫忙。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마침 대규모의 군수품을 양산할 방법이 필요한 상황이었거든.","JPN":"ちょうど大規模な軍需品を量産する方法が必要な状況だったんだ。","ENG":"It just so happens that I need a way to mass-produce large-scale munitions.","TWN":"正好我需要知道大規模生產軍火的方法，"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"서로 간에 건설적인 전략적 제휴를 맺을 수 있을 것 같아.","JPN":"お互いにとって前向きな戦略的提携を結ぶことができそうだな。","ENG":"I think it would be a great idea to partner up together.","TWN":"或許我們可以策略結盟。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네! 좋아요!","JPN":"はい！　喜んで！","ENG":"Okay! Sounds great!","TWN":"好的！沒問題！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……들어보지도 않고? 조금 성급하지 않나?","JPN":"……詳細を聞かなくてもいいのか？　判断が早すぎると思うが。","ENG":"But you haven’t even heard me out... Don’t you think you’re rushing this a little?","TWN":"……你都還沒聽完呢？會不會答應得太快？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"괜찮아요! 사장님이 하시는 일이라면 정말 필요한 일일 테니까요.","JPN":"大丈夫です！　社長のお仕事なら、本当に必要なことでしょうから。","ENG":"It's okay! If you need to do that, that will be something necessary.","TWN":"沒關係！老闆的事一定是很重要的事！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"믿어줘서 고맙군.","JPN":"信じてくれてありがとう。","ENG":"I really appreciate what you’re doing.","TWN":"謝謝你相信我。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"상황이 제법 급박하니 같이 가면서 설명해 주지.","JPN":"状況がかなり緊迫しているから、歩きながら説明しよう。","ENG":"Come with me. I’m on a tight schedule, so I’ll explain on the way.","TWN":"現在情況有點緊急，我們邊走邊說吧？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 세상의 비밀들과 자네가 태어난 사명에 대해서 말이야.","JPN":"この世界の秘密や君が生まれた使命についてね。","ENG":"It’s about this world’s secrets and your purpose for being born.","TWN":"是關於這個世界的秘密，和你出生的使命。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이 세상의…… 비밀이요?","JPN":"この世界の……秘密ですか？","ENG":"The world’s... secrets?","TWN":"這個世界的……秘密？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 혹시 지아 양은 구 관리국과 관리 실패에 대해 얼마나 알고 있나?","JPN":"ああ。ユイは旧管理局と管理失敗についてどれくらい知っているかね？","ENG":"Yes. Jia, how much do you know about the collapse of the Old Administration?","TWN":"對，有關舊管理局和管理失敗的事，你知道多少？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};